import { describe, expect, test } from '@a0n/gnosis/test';
import { readFileSync } from 'node:fs';

import {
  AEON_PAIR_CARRIER_CAPACITY,
  BWTR_FIXTURES,
  BWTR_HEADER_LEN,
  BWTR_MAGIC_BYTES,
  aeonPairCarrierKey,
  canonicalC2CarrierKey,
  c2SwapBoundaryCarrierKey,
  clockPhaseForTritonAdmission,
  encodeResidentBinaryTritonPayload,
  evaluateTritonAdmission,
  isValidAeonPairCarrierKey,
  parseResidentTritonPayload,
  residentGnosisClockPhaseOfNatTick,
} from './triton-admission-gate';

describe('triton admission gate', () => {
  test('maps fork/race/fold phases onto the GnosisClock Triton slots', () => {
    expect(clockPhaseForTritonAdmission('race-fold-present')).toBe(0);
    expect(clockPhaseForTritonAdmission('fork-future')).toBe(1);
    expect(clockPhaseForTritonAdmission('vent-interfere-past')).toBe(11);
  });

  test('indexes the saturated twelve-slot carrier as 66 strict pairs', () => {
    expect(AEON_PAIR_CARRIER_CAPACITY).toBe(66);
    expect(aeonPairCarrierKey(0, 1)).toBe(0);
    expect(aeonPairCarrierKey(0, 2)).toBe(1);
    expect(aeonPairCarrierKey(1, 2)).toBe(11);
    expect(aeonPairCarrierKey(10, 11)).toBe(65);
  });

  test('rejects invalid pair coordinates and carrier keys', () => {
    expect(() => aeonPairCarrierKey(1, 1)).toThrow(RangeError);
    expect(() => aeonPairCarrierKey(2, 1)).toThrow(RangeError);
    expect(() => aeonPairCarrierKey(-1, 1)).toThrow(RangeError);
    expect(isValidAeonPairCarrierKey(-1)).toBe(false);
    expect(isValidAeonPairCarrierKey(66)).toBe(false);
    expect(isValidAeonPairCarrierKey(65)).toBe(true);
  });

  test('collapses the C2 boundary duplicate before admission', () => {
    expect(c2SwapBoundaryCarrierKey(0)).toBe(1);
    expect(c2SwapBoundaryCarrierKey(1)).toBe(0);
    expect(c2SwapBoundaryCarrierKey(2)).toBe(2);
    expect(canonicalC2CarrierKey(0)).toBe(0);
    expect(canonicalC2CarrierKey(1)).toBe(0);
    expect(canonicalC2CarrierKey(2)).toBe(2);
  });

  test('rejects work on the wrong Triton clock slot', () => {
    expect(
      evaluateTritonAdmission({
        phase: 'fork-future',
        clockPhase: 0,
      })
    ).toMatchObject({
      status: 'reject',
      reason: 'triton-clock-phase-mismatch',
      expectedClockPhase: 1,
    });
  });

  test('defers future forks when the admission budget is exhausted', () => {
    expect(
      evaluateTritonAdmission({
        phase: 'fork-future',
        clockPhase: 1,
        forkBudget: 0,
      })
    ).toMatchObject({
      status: 'defer',
      reason: 'fork-budget-exhausted',
    });
  });

  test('rejects duplicate work under the C2 canonical carrier key', () => {
    expect(
      evaluateTritonAdmission({
        phase: 'race-fold-present',
        clockPhase: 0,
        carrierKey: 1,
        seenCanonicalC2Keys: new Set([0]),
      })
    ).toMatchObject({
      status: 'reject',
      reason: 'c2-duplicate-carrier',
      canonicalC2Key: 0,
    });
  });

  test('admits valid carrier work with canonical metadata', () => {
    expect(
      evaluateTritonAdmission({
        phase: 'race-fold-present',
        clockPhase: 0,
        carrierKey: 11,
      })
    ).toMatchObject({
      status: 'admit',
      reason: 'triton-carrier-admitted',
      carrierKey: 11,
      canonicalC2Key: 11,
    });
  });

  test('maps resident fallback ticks through the GnosisClock phaseOfNatTick', () => {
    expect(residentGnosisClockPhaseOfNatTick(0)).toBe(0);
    expect(residentGnosisClockPhaseOfNatTick(11)).toBe(11);
    expect(residentGnosisClockPhaseOfNatTick(12)).toBe(0);
    expect(residentGnosisClockPhaseOfNatTick(13)).toBe(1);
  });

  test('round-trips the public BWTR v1 fixture shared with Rust', () => {
    const [fixture] = BWTR_FIXTURES;
    expect(fixture).toBeDefined();
    const artifact = loadBwtrFixtureArtifact();
    const artifactFixture = artifact.fixtures.find(
      (entry) => entry.name === fixture.name
    );
    expect(artifact.leanTheorem).toBe(
      'Gnosis.PleromaAeonMonsterBridge.bwtr_fixture_roundtrip'
    );
    expect(artifactFixture).toBeDefined();
    expect(artifactFixture?.hex).toBe(fixture.hex);
    expect(artifactFixture?.userId).toBe(fixture.userId);

    const encoded = encodeResidentBinaryTritonPayload(
      fixture.work,
      fixture.userId
    );
    expect(encoded.slice(0, 4)).toEqual(BWTR_MAGIC_BYTES);
    expect(encoded.length).toBe(BWTR_HEADER_LEN + fixture.userId.length);
    expect(toHex(encoded)).toBe(fixture.hex);
    expect([...encoded]).toEqual(artifactFixture?.bytes);

    const parsed = parseResidentTritonPayload(encoded, 0);
    expect(parsed.userId).toBe(fixture.userId);
    expect(parsed.work.phase).toBe(fixture.work.phase);
    expect(parsed.work.clockPhase).toBe(fixture.work.clockPhase);
    expect(parsed.work.carrierKey).toBe(fixture.work.carrierKey);
    expect(parsed.work.forkBudget).toBe(fixture.work.forkBudget);
    expect(parsed.work.seenCanonicalC2Keys).toEqual(
      fixture.work.seenCanonicalC2Keys
    );
  });

  test('parses text metadata and plain user fallback with BWTR precedence', () => {
    const text = new TextEncoder().encode(
      'triton:phase=race-fold-present,clock=0,carrier=11,budget=2,seen=3;user-123'
    );
    expect(parseResidentTritonPayload(text, 13)).toMatchObject({
      userId: 'user-123',
      work: {
        phase: 'race-fold-present',
        clockPhase: 0,
        carrierKey: 11,
        forkBudget: 2,
      },
    });

    const plain = parseResidentTritonPayload(
      new TextEncoder().encode('user-plain'),
      13
    );
    expect(plain).toMatchObject({
      userId: 'user-plain',
      work: { phase: 'race-fold-present', clockPhase: 1 },
    });
  });
});

function toHex(bytes: Uint8Array): string {
  return [...bytes].map((byte) => byte.toString(16).padStart(2, '0')).join('');
}

type BwtrFixtureArtifact = Readonly<{
  leanTheorem: string;
  fixtures: readonly Readonly<{
    name: string;
    hex: string;
    bytes: readonly number[];
    userId: string;
  }>[];
}>;

function loadBwtrFixtureArtifact(): BwtrFixtureArtifact {
  return JSON.parse(
    readFileSync('polyglot/tests/fixtures/bwtr-v1.json', 'utf8')
  ) as BwtrFixtureArtifact;
}
